import json

# Check if files exist first
import os

files = [
    'file_storage/functions.query_db:10.json',
    'file_storage/functions.query_db:11.json'
]

file_info = {}
for file in files:
    exists = os.path.exists(file)
    file_info[file] = {
        'exists': exists,
        'size': os.path.getsize(file) if exists else 0
    }

print('__RESULT__:')
print(json.dumps(file_info))

